#include <stdio.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        int arr[1000];
        for(int i=0;i<n;++i) scanf("%d",&arr[i]);
        for(int i=n-1;i>=0;--i){
            printf("%d",arr[i]);
            if(i) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

